index|idx_artifacts_work_entry_id|CREATE INDEX idx_artifacts_work_entry_id ON artifacts(work_entry_id)
index|idx_notes_work_entry_id|CREATE INDEX idx_notes_work_entry_id ON notes(work_entry_id)
index|idx_work_entries_created_at|CREATE INDEX idx_work_entries_created_at ON work_entries(created_at)
index|idx_work_entries_status|CREATE INDEX idx_work_entries_status ON work_entries(status)
index|idx_work_entry_tags_tag_id|CREATE INDEX idx_work_entry_tags_tag_id ON work_entry_tags(tag_id)
table|artifacts|CREATE TABLE artifacts ( id INTEGER PRIMARY KEY AUTOINCREMENT, work_entry_id TEXT NOT NULL REFERENCES work_entries(id) ON DELETE CASCADE, type TEXT NOT NULL, value TEXT NOT NULL, created_at TEXT NOT NULL, UNIQUE (work_entry_id, type, value) )
table|notes|CREATE TABLE notes ( id INTEGER PRIMARY KEY AUTOINCREMENT, work_entry_id TEXT NOT NULL REFERENCES work_entries(id) ON DELETE CASCADE, path TEXT NOT NULL, date TEXT NOT NULL, created_at TEXT NOT NULL, UNIQUE (work_entry_id, path, date) )
table|state|CREATE TABLE state ( id INTEGER PRIMARY KEY CHECK (id = 1), selected_work_entry_id TEXT REFERENCES work_entries(id) ON DELETE SET NULL, last_health_check TEXT, dock_root TEXT, dock_auto_create INTEGER NOT NULL DEFAULT 0 CHECK (dock_auto_create IN (0, 1)) )
table|tags|CREATE TABLE tags ( id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL UNIQUE )
table|work_entries|CREATE TABLE work_entries ( id TEXT PRIMARY KEY, title TEXT NOT NULL UNIQUE COLLATE NOCASE, description TEXT, status TEXT NOT NULL DEFAULT 'new' COLLATE NOCASE, status_reason TEXT, pad_path TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL )
table|work_entry_tags|CREATE TABLE work_entry_tags ( work_entry_id TEXT NOT NULL REFERENCES work_entries(id) ON DELETE CASCADE, tag_id INTEGER NOT NULL REFERENCES tags(id) ON DELETE CASCADE, PRIMARY KEY (work_entry_id, tag_id) )
